function qaClean(v) { return String(v ?? '').replace(/\s+/g, ' ').trim(); }
function qaHas(text, needle) { return qaClean(text).toLowerCase().includes(String(needle).toLowerCase()); }
function qaNoBadText(out) {
  const s = String(out?.output || out?.message || out?.['Ответ'] || '');
  const bad = [];
  if (/v15\.0|v16\.0|v17\.0|v18\.0|v19\.0|v20\.0|v15-|v16-|v17-|v18-|v19-|v20-/i.test(s)) bad.push('в ответе всплыла старая версия v15/v16/v17/v18/v19/v20');
  if (/\\n\s*\d+\./.test(s)) bad.push('в ответе есть literal \\n2.');
  if (/(\d+\s*ноч(?:и|ей))\s*·\s*\1/i.test(s)) bad.push('дублируются ночи');
  if (/Лучшее решение[\s\S]{0,500}ТОЛЬКО ЕСЛИ НУЖНА МИНИМАЛЬНАЯ ЦЕНА/i.test(s)) bad.push('слабый дешевый вариант попал в лучшее решение');
