  return result;
}

function parseBudget(text) {
  const s = cleanText(text).toLowerCase().replace(/ё/g, 'е').replace(/,/g, '.');
  let raw = null;

  // v17: бюджет считаем общим, если пользователь пишет "на двоих/на троих/на всех".
  // Не цепляем числа из дат и ночей: 11.07, 18.07, 6-7 ночей.
  const explicitMoneyPatterns = [
    /(?:до|бюджет|макс(?:имум)?|лимит|не\s*дороже|цена|стоимость|около|примерно)\s*(\d{2,3}(?:\s?\d{3})+|\d{5,7})\s*(?:₽|руб|рублей|р|rub)?/i,
    /(\d{2,3}(?:\s?\d{3})+|\d{5,7})\s*(?:₽|руб|рублей|р|rub)\b/i
  ];
  for (const re of explicitMoneyPatterns) {
    const m = s.match(re);
    if (m) { raw = Number(String(m[1]).replace(/\D/g, '')); break; }
  }
  if (!raw) {
    const mPersonRaw = s.match(/(\d{5,7})\s*(?:₽|руб|рублей|р|rub)?\s*(?:с\s*человека|на\s*(?:1|одного|человека|персону|каждого)|за\s*человека)/i);
    if (mPersonRaw) raw = Number(String(mPersonRaw[1]).replace(/\D/g, ''));
  }
  if (!raw) {
    const mK = s.match(/(?:до|бюджет|макс(?:имум)?|лимит|цена|стоимость|за|не\s*дороже|около|примерно)?\s*(\d+(?:[.]\d+)?)\s*(?:тыс|тысяч|к|k)(?:\b|\s|$)/i);
    if (mK) raw = Math.round(Number(mK[1]) * 1000);
  }
  if (!raw) raw = 175000;

  const perPerson = /на\s*(?:1|одного|человека|персону)|с\s*человека|за\s*человека|на\s*каждого/i.test(s);
  // "бюджет 175000 на двоих" = общий бюджет. Но "120000 с человека на двоих" = умножаем.
  if (perPerson) raw = raw * (parseAdults(text) + parseChildren(text));
  return raw;
}

function parseAdults(text) {
  const s = cleanText(text).toLowerCase().replace(/ё/g, 'е');
  if (/на\s*двоих|2\s*взросл|двое|пара|я\s*и\s*(?:жена|муж|девушка|парень)|муж\s*и\s*жена/i.test(s)) return 2;
