  if (m) return Number(m[1]);
  if (/один|solo|соло|одному|одна/i.test(s)) return 1;
  return 2;
}
function parseChildren(text) {
  const s = cleanText(text).toLowerCase().replace(/ё/g, 'е');
  let m = s.match(/(\d+)\s*(?:реб|дет|child|kid)/i);
  if (m) return Number(m[1]);
  m = s.match(/(?:ребенок|ребенка|ребенком|дитя|child|kid)\s*(\d{1,2})?\s*(?:лет|года|год)?/i);
  if (m) return 1;
  m = s.match(/(?:с|и)\s*(?:одним\s*)?(?:ребенком|ребенок|детьми)/i);
  if (m) return 1;
  m = s.match(/(\d+)\s*\+\s*(\d+)/);
  if (m) return Number(m[2]);
  if (/семья\s*с\s*детьми|семейный\s*отдых\s*с\s*детьми/i.test(s)) return 1;
  return 0;
}
function parseNightsFromText(text) {
  const s = cleanText(text).toLowerCase();
  const matches = [...s.matchAll(/(?:на\s*)?(\d{1,2})\s*(?:ноч(?:ь|и|ей)|ноч\.?|nights?)/gi)]
    .map(m => Number(m[1]))
    .filter(n => Number.isFinite(n) && n >= 1 && n <= 30);
  if (matches.length) return matches[matches.length - 1];
  const dayMatches = [...s.matchAll(/(?:на\s*)?(\d{1,2})\s*(?:дн(?:я|ей)|день|days?)/gi)]
    .map(m => Number(m[1]))
    .filter(n => Number.isFinite(n) && n >= 2 && n <= 31);
  if (dayMatches.length) return Math.max(1, dayMatches[dayMatches.length - 1] - 1);
  return null;
}

function parseDurationRequest(text, vacationDays = null) {
  const s = cleanText(text).toLowerCase().replace(/ё/g, 'е');
  const clamp = (n) => Math.max(1, Math.min(30, Number(n || 0)));
  const normalizeRange = (a, b, source) => {
    let x = clamp(a);
    let y = clamp(b);
    if (x > y) [x, y] = [y, x];
    return { explicit: true, min: x, max: y, ideal: y, isRange: x !== y, source, label: x === y ? `${x} ночей` : `${x}–${y} ночей` };
  };
  let m = s.match(/(\d{1,2})\s*(?:-|–|—|до|по|или|\/|\\)\s*(\d{1,2})\s*(?:ноч(?:ь|и|ей)|ноч\.?|nights?)/i);
  if (m) return normalizeRange(Number(m[1]), Number(m[2]), 'explicit_nights_range');
  m = s.match(/(\d{1,2})\s*(?:-|–|—|до|по|или|\/|\\)\s*(\d{1,2})\s*(?:дн(?:я|ей)|день|days?)/i);
  if (m) return normalizeRange(Number(m[1]) - 1, Number(m[2]) - 1, 'explicit_days_range');
  const n = parseNightsFromText(text);
  if (n) return { explicit: true, min: n, max: n, ideal: n, isRange: false, source: /дн(?:я|ей)|день|days?/i.test(s) ? 'explicit_days' : 'explicit_nights', label: `${n} ночей` };
  if (vacationDays && vacationDays >= 5 && vacationDays <= 21) return { explicit: false, min: Math.max(4, vacationDays - 2), max: vacationDays, ideal: vacationDays, isRange: true, source: 'vacation_window_flexible', label: `${Math.max(4, vacationDays - 2)}–${vacationDays} ночей` };
  return { explicit: false, min: 7, max: 7, ideal: 7, isRange: false, source: 'default_7_nights', label: '7 ночей' };
}
function nightsInAcceptedRange(n, minN, maxN) {
  const x = Number(n || 0);
  return Number.isFinite(x) && x >= minN && x <= maxN;
}
function nightsDistanceToRange(n, minN, maxN) {
