    output,
    message: output,
    'Дата': started,
    'Запрос': `__QA_AUTOPILOT_${AGENT_VERSION}_${$now.toFormat('yyyyMMdd_HHmm')}`,
    'Страна': 'QA',
    'Месяц': '-',
    'Бюджет': '-',
    'Взрослых': '-',
    'Найдено всего': tests.length,
    'Подходят': failed.length ? 0 : 1,
    'Ночей': 'QA',
    'Лучшие варианты': lines.join('\n'),
    'Ответ': output,
    version: AGENT_VERSION,
    qaAutopilot: true,
    qaStatus: status,
    qaFailed: failed.length
  }}];
}

if (QA_REQUESTED) {
  return await runAutonomousQa.call(this);
}

const normalResult = await runAgentCase.call(this, rawText ? rawInput : { chatInput: rawInput.chatInput || rawInput.input || rawInput.message || rawInput.text || rawInput.query || rawInput['Запрос'] || '' });
return [{ json: normalResult }];

const input = $input.first()?.json || {};
const output = input['Ответ'] || input.output || input.message || 'Готово. Результат записан в Google Sheets.';
return [{ json: { ...input, output, message: output, chatOutput: output, returnedToChat: true } }];
